from microcoapy import CoAP, Resource

class TemperatureSensor(Resource):
    def __init__(self):
        super().__init__(path='sensors/temp')
        self.temperature = 25.0  # Default temperature value

    def get(self):
        return str(self.temperature).encode('utf-8')

    def put(self, payload):
        try:
            self.temperature = float(payload.decode('utf-8'))
            return b'Updated'
        except ValueError:
            return b'Invalid Value'

class LightActuator(Resource):
    def __init__(self):
        super().__init__(path='actuators/light')
        self.state = 'off'  # Default state

    def get(self):
        return self.state.encode('utf-8')

    def put(self, payload):
        new_state = payload.decode('utf-8')
        if new_state in ['on', 'off']:
            self.state = new_state
            return b'Updated'
        return b'Invalid State'

def main():
    coap = CoAP()
    coap.add_resource(TemperatureSensor())
    coap.add_resource(LightActuator())
    coap.listen(port=5683)

if __name__ == '__main__':
    main()